// Loop over input items and add a new field called "phoneNumbers" to the JSON of each one
let data = $('WhatsApp Trigger').all()
for (const item of data) {
  // Extraer el número del campo "from"
  const whatsappNumber = item.json.messages[0].from;

  // Remover el código de país de Argentina (54) y el 9 adicional de WhatsApp
  // Formato WhatsApp: 549387468167* -> extraemos 3874681678
  let localNumber = whatsappNumber.replace('54', '').replace('9', '');
  let completeNumber = whatsappNumber.replace(/^549/, "54");

  // Crear los dos formatos solicitados
  const phoneNumbers = {
    withoutPrefix: localNumber,           // 3874681678
    withPrefix: completeNumber
  };

  // Agregar el nuevo campo al objeto
  item.json.phoneNumbers = phoneNumbers;
}

return data;

